nodes.notes:
接收 POST 请求更新任意业务板块的 OKR 进度

请求体格式：
{
  "business": "maoai",  // 业务ID
  "objectiveIndex": 0,   // 第几个O（0-based）
  "krIndex": 0,         // 第几个KR（0-based）
  "progress": 75        // 新进度 0-100
}
或批量更新：
{
  "action": "batch",
  "updates": [...]
}
或完全替换数据：
{
  "action": "replace",
  "data": { ...完整OKR_DATA... }
}

parameters.jsCode:
// 批量更新：遍历 updates 数组，逐个应用到当前数据
const rawBody = $input.first().json.rawBody;
const updates = rawBody.updates;

// 从 Supabase 获取当前数据（这里用默认数据作为fallback）
// 实际生产中应从 Supabase table 读取
let currentData = {
  meta: { year: 2026, currentQuarter: 'Q1', lastUpdated: null },
  businesses: []
};

for (const update of updates) {
  const biz = currentData.businesses.find(b => b.id === update.business);
  if (biz) {
    if (update.objectiveIndex !== undefined && update.krIndex !== undefined) {
      const obj = biz.objectives[update.objectiveIndex];
      if (obj && obj.keyResults[update.krIndex]) {
        obj.keyResults[update.krIndex].progress = update.progress;
      }
    }
    if (update.overallProgress !== undefined) {
      biz.overallProgress = update.overallProgress;
    }
  }
}

return [{ json: { result: 'batch_updated', count: updates.length, data: currentData } }]

// 单条更新：应用一个 KR 或 overall 的变更
const raw = $input.first().json.rawBody;

// 默认模板数据（生产环境从 Supabase 读取）
let currentData = {
  meta: { year: 2026, currentQuarter: 'Q1', lastUpdated: null },
  businesses: []
};

const biz = currentData.businesses.find(b => b.id === raw.business);
if (biz) {
  if (raw.objectiveIndex !== undefined && raw.krIndex !== undefined) {
    const obj = biz.objectives[raw.objectiveIndex];
    if (obj && obj.keyResults[raw.krIndex]) {
      obj.keyResults[raw.krIndex].progress = raw.progress;
    }
  }
  if (raw.overallProgress !== undefined) {
    biz.overallProgress = raw.overallProgress;
  }
  // Recalculate overall from KRs if not provided
  if (raw.overallProgress === undefined) {
    let totalKr = 0, sumKr = 0;
    for (const o of biz.objectives) {
      for (const kr of o.keyResults) { sumKr += kr.progress; totalKr++; }
    }
    biz.overallProgress = totalKr > 0 ? Math.round(sumKr / totalKr) : 0;
  }
}

return [{ json: { result: 'single_updated', business: raw.business, data: currentData } }]

// ====== 罗盘 HTML 模板引擎 ======
// 从 Supabase 读取最新数据，渲染完整的 Compass Dashboard HTML

const inputItem = $input.first();
let okrData = null;
try {
  okrData = typeof inputItem.json.data === 'string' 
    ? JSON.parse(inputItem.json.data) 
    : inputItem.json.data;
} catch(e) {
  // Fallback: 使用内置默认数据
  okrData = null;
}

// 如果没有外部数据，使用内置默认值
if (!okrData) {
  okrData = {
    meta: { year: 2026, currentQuarter: 'Q1', lastUpdated: new Date().toISOString() },
    businesses: [
      // （完整默认数据见 compass.html 内 OKR_DATA 对象）
      // 这里为了 workflow 简洁，实际HTML自带默认数据
    ]
  };
}

// 注入标记：让 HTML 页面知道数据来自 n8n
const injectedScript = `
window.__OKR_INJECTED__ = ${JSON.stringify(okrData)};`;

return [{ json: { htmlGenerated: true, recordCount: 1, dataTimestamp: okrData?.meta?.lastUpdated || 'N/A' } }]

// 最终组装：将动态数据注入静态 HTML 模板
const templateItem = $input.item.find(i => i.binary?.data);
const renderItem = $input.item.find(i => i.json?.htmlGenerated);

let html = '';
if (templateItem) {
  const buffer = templateItem.binary.data.data;
  html = buffer.toString('utf8');
}

// 在 </body> 标签前注入实时数据
const injectionPoint = '</body>';
const injectedData = renderItem?.json || {};
const scriptTag = `<script>window.__OKR_INJECTED__=${JSON.stringify(injectedData.okrData || {})};</script>`;

if (html.includes(injectionPoint)) {
  html = html.replace(injectionPoint, scriptTag + '\n' + injectionPoint);
} else {
  html += scriptTag;
}

return [{ json: { outputHtml: html, generatedAt: new Date().toISOString(), size: html.length } }]
